  async function renderReportPreview() {
    if (!state.ranking.length) {
      setHtml('reportPreview', '<div class="message info">Run the analysis to generate the report preview.</div>');
      updateProjectSummaryBox();
      return;
    }
    const html = await buildReportHtml({ rasteriseCharts: false, chartColumns: 1 });
    const body = html.match(/<body[^>]*>([\s\S]*)<\/body>/i);
    const staleNote = resultsAreCurrent() ? '' :
      '<div class="message warning">These figures are out of date because the data or settings changed since the last analysis. Run the Benefit-Cost Analysis again before exporting; export is disabled until you do.</div>';
    setHtml('reportPreview', staleNote + (body ? body[1] : html));
  }



  function rtfEscape(value) {
    return String(value ?? '')
      .replace(/\r\n|\r/g, '\n')
      .replace(/[\\{}]/g, (m) => `\\${m}`)
      .replace(/[^\x00-\x7F]/g, (ch) => `\\u${ch.charCodeAt(0)}?`)
      .replace(/\n/g, '\\line ');
  }

  function rtfPara(text, { size = 22, bold = false, align = 'left', before = 0, after = 120, color = 0 } = {}) {
    const alignCode = align === 'center' ? '\\qc' : align === 'right' ? '\\qr' : '\\ql';
    const colorCode = color ? `\\cf${color}` : '\\cf0';
    return `\\pard${alignCode}\\sb${before}\\sa${after}\\f0\\fs${size}${colorCode}${bold ? '\\b ' : ' '}${rtfEscape(text)}${bold ? '\\b0' : ''}\\cf0\\par\n`;
  }

  function rtfSectionHeading(text) {
    return rtfPara(text, { size: 28, bold: true, after: 140, color: 1 });
  }

  function rtfSubHeading(text) {
    return rtfPara(text, { size: 23, bold: true, after: 60, color: 1 });
  }

  function rtfTable(rows, widths, alignments = [], headerRows = 1, fontSize = 17) {
    const border = '\\clbrdrt\\brdrs\\brdrw10\\brdrcf2\\clbrdrl\\brdrs\\brdrw10\\brdrcf2\\clbrdrb\\brdrs\\brdrw10\\brdrcf2\\clbrdrr\\brdrs\\brdrw10\\brdrcf2';
    return rows.map((row, rowIndex) => {
      let x = 0;
      let rowDef = '\\trowd\\trgaph70\\trleft0\\trrh260';
      row.forEach((_, i) => {
        x += widths[i] || 1000;
        rowDef += `${border}${rowIndex < headerRows ? '\\clcbpat3' : (rowIndex % 2 === 0 ? '\\clcbpat4' : '')}\\cellx${x}`;
      });
      const cells = row.map((cell, i) => {
        const align = alignments[i] === 'right' ? '\\qr' : alignments[i] === 'center' ? '\\qc' : '\\ql';
        const isHeader = rowIndex < headerRows;
        return `\\pard\\intbl${align}\\sb50\\sa50\\f0\\fs${fontSize}${isHeader ? '\\b\\cf1 ' : '\\cf0 '}${rtfEscape(cell)}${isHeader ? '\\b0' : ''}\\cf0\\cell`;
      }).join('');
      return `${rowDef}${cells}\\row\n`;
    }).join('');
  }

  function isPngBinary(binary) {
    const sig = [137, 80, 78, 71, 13, 10, 26, 10];
    return !!binary && binary.length >= 24 && sig.every((v, i) => binary.charCodeAt(i) === v);
  }

  function isJpegBinary(binary) {
    return !!binary && binary.length >= 4 && binary.charCodeAt(0) === 255 && binary.charCodeAt(1) === 216;
  }

  function pngSizeFromBinary(binary) {
    if (!isPngBinary(binary)) return { width: 1200, height: 600 };
    const read32 = (offset) => ((binary.charCodeAt(offset) << 24) | (binary.charCodeAt(offset + 1) << 16) | (binary.charCodeAt(offset + 2) << 8) | binary.charCodeAt(offset + 3)) >>> 0;
    return { width: read32(16), height: read32(20) };
  }

  function dataUrlToRtfImage(dataUrl, displayWidthTwips = 12240) {
    const match = String(dataUrl || '').match(/^data:([^;]+);base64,(.*)$/);
    if (!match) return '';
    const mime = match[1].toLowerCase();
    const base64 = match[2].replace(/\s+/g, '');
    const binary = atob(base64);
    const isPng = isPngBinary(binary) || mime.includes('png');
    const isJpeg = isJpegBinary(binary) || mime.includes('jpeg') || mime.includes('jpg');
    const size = isPng ? pngSizeFromBinary(binary) : { width: 1200, height: 600 };
    const displayHeightTwips = Math.max(220, Math.round(displayWidthTwips * (size.height / Math.max(1, size.width))));
    const blip = isPng ? 'pngblip' : (isJpeg ? 'jpegblip' : 'pngblip');
    const chunks = [];
    let line = '';
    for (let i = 0; i < binary.length; i += 1) {
      line += binary.charCodeAt(i).toString(16).padStart(2, '0');
      if (line.length >= 128) {
        chunks.push(line);
        line = '';
      }
    }
    if (line) chunks.push(line);
    return `{\\pict\\${blip}\\picw${size.width}\\pich${size.height}\\picwgoal${displayWidthTwips}\\pichgoal${displayHeightTwips}\n${chunks.join('\n')}\n}`;
  }

  function blobToDataUrl(blob) {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = () => resolve(String(reader.result || ''));
      reader.onerror = () => resolve('');
      reader.readAsDataURL(blob);
    });
  }

  function imageSourceToPngDataUrl(src) {
    return new Promise((resolve) => {
      const img = new Image();
      img.onload = () => {
        try {
          const canvas = document.createElement('canvas');
          canvas.width = img.naturalWidth || img.width || 1;
          canvas.height = img.naturalHeight || img.height || 1;
          const ctx = canvas.getContext('2d');
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0);
          resolve(canvas.toDataURL('image/png'));
        } catch (error) {
          resolve('');
        }
      };
      img.onerror = () => resolve('');
      img.src = src;
    });
  }

  async function assetToDataUrl(src, fallback = '') {
    if (!src && !fallback) return '';
    // Use the embedded fallback first for the Word report. This avoids missing logos when
    // files are opened locally, when fetch() is blocked, or when Word cannot resolve
    // external image references.
    if (fallback) return fallback;
    try {
      const response = await fetch(src, { cache: 'force-cache' });
      if (response.ok) {
        const dataUrl = await blobToDataUrl(await response.blob());
        return dataUrl || '';
      }
    } catch (error) {
      // Some local file workflows block fetch(). The image/canvas fallback below covers those cases.
    }
    return imageSourceToPngDataUrl(src);
  }

  /* Rasterise an SVG (or any image) data URI to a PNG data URL at an explicit
     square pixel size. RTF/Word cannot embed SVG, so the approved SVG logo is
     converted to a high-resolution PNG at export time using the browser canvas
     (the same mechanism already used for the chart images). The logo artwork is
     preserved exactly — it is only rasterised, never recoloured or reshaped. */
  function rasteriseSvgToPng(src, size = 640) {
    return new Promise((resolve) => {
      if (!src) { resolve(''); return; }
      const img = new Image();
      img.onload = () => {
        try {
          const ratio = img.naturalWidth && img.naturalHeight ? img.naturalHeight / img.naturalWidth : 1;
          const canvas = document.createElement('canvas');
          canvas.width = size;
          canvas.height = Math.max(1, Math.round(size * ratio));
          const ctx = canvas.getContext('2d');
          ctx.clearRect(0, 0, canvas.width, canvas.height);
          ctx.imageSmoothingEnabled = true;
          ctx.imageSmoothingQuality = 'high';
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          resolve(canvas.toDataURL('image/png'));
        } catch (_) {
          resolve('');
        }
      };
      img.onerror = () => resolve('');
      img.src = src;
    });
  }

  async function loadReportLogoImages() {
    const includeLogos = $('includeReportLogos')?.value !== 'no';
    if (!includeLogos) return { uon: '', soil: '' };
    // The approved UON logo is an SVG; rasterise it for the .doc/RTF export.
    // The SOIL CRC logo remains the existing approved PNG badge.
    const [uon, soil] = await Promise.all([
      rasteriseSvgToPng(REPORT_LOGO_UON, 660),
      assetToDataUrl('logo_soil_crc.png', EMBEDDED_WORD_LOGOS.soil)
    ]);
    return { uon, soil };
  }

  function rtfLogoBlock(logos, placement = 'header') {
    if (!logos?.uon && !logos?.soil) return '';
    const after = placement === 'footer' ? 110 : 170;
    const uon = logos.uon ? dataUrlToRtfImage(logos.uon, placement === 'footer' ? 1000 : 1450) : '';
    const soil = logos.soil ? dataUrlToRtfImage(logos.soil, placement === 'footer' ? 1200 : 1650) : '';
    if (!uon && !soil) return '';
    // Use a simple two-column RTF table so Word lays out both embedded logos reliably.
    return `\\pard\\qc\\sa${after}\n` +
      `\\trowd\\trgaph80\\trleft2300\\cellx6200\\cellx10100` +
      `\\pard\\intbl\\qc ${uon || ''}\\cell` +
      `\\pard\\intbl\\qc ${soil || ''}\\cell\\row\n`;
  }

  async function collectRtfCharts() {
    const control = state.ranking.find((r) => r.isControl) || null;
    const charts = [];
    for (const [index, id] of FIGURE_IDS.entries()) {
      const svg = $(id)?.innerHTML || '';
      const dataUrl = /\<svg/i.test(svg) ? await svgToPngDataUrl(svg, 2200) : '';
      charts.push({ index: index + 1, id, title: chartTitle(id), caption: chartCaption(id, control), dataUrl });
    }
    return charts;
  }

  function buildRtfNarrative(text) {
    const cleaned = String(text || '').replace(/\\n/g, '\n').trim();
    if (!cleaned) return '';
    return cleaned.split(/\n\s*\n+/).filter(Boolean).map((block) => {
      const parts = block.split(/\n/).map((part) => part.trim()).filter(Boolean);
      const heading = normaliseReportHeading(parts.shift());
      const body = tidySentence(parts.join(' '));
      return rtfSubHeading(heading) + rtfPara(body, { size: 22, after: 180 });
    }).join('');
  }

